const stars = document.querySelector('feed-stars');
stars.addEventListener('change', (e) => {
  console.log('New rating:', e.detail.value); // 1–5, or 0 when cleared
});

const globe = document.querySelector('flow-globe');
globe.setData([
  { sourceId: 'US', targetId: 'DE', value: 120 },
  { sourceId: 'DE', targetId: 'GB', value: 70 }
]);

const map = document.querySelector('kerala-district-map');
map.setData({
  ernakulam: { value: 86, segment: 'Growth' },
  thiruvananthapuram: { value: 83, segment: 'Capital' },
  'ഇടുക്കി': { value: 58, segment: 'High range' }
});

document.querySelector('kerala-district-map')
  .addEventListener('district-select', (event) => {
    const { slug, displayName, value, data } = event.detail;
    console.log(slug, displayName, value, data);
  });

kerala-district-map {
  --kerala-district-map-overlay-background: rgba(255,255,255,.72);
  --kerala-district-map-overlay-backdrop-filter: blur(18px) saturate(1.35);
  --kerala-district-map-popup-background: rgba(255,255,255,.82);
  --kerala-district-map-popup-backdrop-filter: blur(18px) saturate(1.35);
}

const reactions = document.querySelector('mood-reactions');
reactions.addEventListener('change', (e) => {
  console.log('Selected:', e.detail.value, e.detail.item?.label);
});

const faces = document.querySelector('pulse-faces[selectable]');
faces.addEventListener('change', (e) => {
  console.log('Selected:', e.detail.value, e.detail.item);
});

const maze = document.querySelector('spin-maze');
maze.addEventListener('complete', (e) => {
  console.log('Completed level:', e.detail.level);
  console.log('All completed:', e.detail.completedLevels);
});
